import React, { useState } from 'react';
import {
  Box,
  Typography,
  Paper,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  IconButton,
  Chip,
  useTheme,
  Card,
  CardContent,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Divider,
  Tabs,
  Tab,
  SelectChangeEvent
} from '@mui/material';
import { 
  Add, 
  Edit, 
  Delete, 
  MoreVert, 
  Visibility, 
  CarRental, 
  People, 
  MonetizationOn,
  CardGiftcard,
  Settings,
  DirectionsCar,
  Business,
  Storage
} from '@mui/icons-material';
import { styled, alpha } from '@mui/material/styles';
import { motion } from 'framer-motion';
import { useFirebase } from '../context/FirebaseContext';
import { addDoc, updateDoc, deleteDoc, doc, collection } from 'firebase/firestore';
import { db } from '../firebase/config';
import { Raffle } from '../types';
import CarSpecificationsForm from '../components/admin/CarSpecificationsForm';
import CompaniesManager from '../components/admin/CompaniesManager';
import DatabaseMigration from '../components/admin/DatabaseMigration';
import AppSettingsForm from '../components/admin/AppSettingsForm';
import CarSpecificationsModal from '../components/CarSpecificationsModal';

const AdminHeader = styled(Paper)(({ theme }) => ({
  padding: theme.spacing(3),
  borderRadius: theme.spacing(2),
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: theme.spacing(3),
  background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  color: 'white',
  boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
}));

const StatsCard = styled(Card)(({ theme }) => ({
  borderRadius: theme.spacing(2),
  boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
  height: '100%',
  transition: 'transform 0.2s ease, box-shadow 0.2s ease',
  '&:hover': {
    transform: 'translateY(-5px)',
    boxShadow: '0 8px 24px rgba(0,0,0,0.1)',
  },
}));

const StatsIcon = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 60,
  height: 60,
  borderRadius: '50%',
  marginBottom: theme.spacing(2),
  backgroundColor: alpha(theme.palette.primary.main, 0.1),
  color: theme.palette.primary.main,
}));

const TablePaper = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(2),
  overflow: 'hidden',
  boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
  marginBottom: theme.spacing(4),
}));

// Компонент для панели с разными вкладками
const TabPanel = (props: { children?: React.ReactNode; index: number; value: number }) => {
  const { children, value, index, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`admin-tabpanel-${index}`}
      aria-labelledby={`admin-tab-${index}`}
      style={{ padding: '16px 0' }}
      {...other}
    >
      {value === index && children}
    </div>
  );
};

// Создаем компоненты-обертки для замены Grid
interface GridContainerProps {
  children: React.ReactNode;
  spacing?: number;
  sx?: any;
  [key: string]: any;
}

const GridContainer: React.FC<GridContainerProps> = ({ children, spacing = 0, ...props }) => (
  <Box 
    sx={{ 
      display: 'flex', 
      flexWrap: 'wrap', 
      margin: spacing ? `-${spacing * 4}px` : 0,
      width: spacing ? `calc(100% + ${spacing * 8}px)` : '100%',
      ...props.sx
    }}
    {...props}
  >
    {children}
  </Box>
);

interface GridItemProps {
  children: React.ReactNode;
  xs?: number;
  md?: number;
  sx?: any;
  [key: string]: any;
}

const GridItem: React.FC<GridItemProps> = ({ children, xs, md, ...props }) => {
  // Определяем ширину в зависимости от брейкпоинтов
  const widthStyles: Record<string, string> = {};
  
  if (xs) {
    widthStyles.xs = xs === 12 ? '100%' : `${(xs / 12) * 100}%`;
  }
  
  if (md) {
    widthStyles.md = md === 12 ? '100%' : `${(md / 12) * 100}%`;
  }
  
  return (
    <Box 
      sx={{ 
        padding: 2,
        boxSizing: 'border-box',
        flexShrink: 0,
        ...props.sx,
        width: { xs: '100%', ...widthStyles }
      }}
      {...props}
    >
      {children}
    </Box>
  );
};

const AdminPage: React.FC = () => {
  const theme = useTheme();
  const { raffles, companies, refreshData } = useFirebase();
  const [tabValue, setTabValue] = useState(0);
  const [openDialog, setOpenDialog] = useState(false);
  const [editRaffle, setEditRaffle] = useState<Raffle | null>(null);
  const [openCarSpecsDialog, setOpenCarSpecsDialog] = useState(false);
  const [selectedRaffle, setSelectedRaffle] = useState<Raffle | null>(null);
  const [viewCarSpecsModal, setViewCarSpecsModal] = useState(false);
  const [form, setForm] = useState<any>({
    title: '',
    image: '',
    description: '',
    totalTickets: '',
    ticketsSold: 0,
    price: '',
    status: 'draft',
    endDate: '',
    companyId: '',
    year: '',
    participants: 0
  });
  
  // Данные статистики
  const statsData = [
    { 
      title: 'Всего розыгрышей', 
      value: raffles.length, 
      icon: <CardGiftcard sx={{ fontSize: 30 }} />,
      change: `${raffles.filter(r => r.status === 'active').length} активных`
    },
    { 
      title: 'Активных участников', 
      value: raffles.reduce((sum, raffle) => sum + (raffle.participants || 0), 0), 
      icon: <People sx={{ fontSize: 30 }} />,
      change: 'Все розыгрыши'
    },
    { 
      title: 'Продано билетов', 
      value: raffles.reduce((sum, raffle) => sum + raffle.ticketsSold, 0), 
      icon: <MonetizationOn sx={{ fontSize: 30 }} />,
      change: 'Все розыгрыши'
    },
  ];
  
  const handleTabChange = (_event: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
  };
  
  // Открыть диалог создания/редактирования
  const handleOpenDialog = (raffle?: any) => {
    if (raffle) {
      setEditRaffle(raffle);
      setForm({ ...raffle });
    } else {
      setEditRaffle(null);
      setForm({
        title: '', image: '', description: '', totalTickets: '', ticketsSold: 0, price: '', status: 'draft', endDate: '', companyId: '', year: '', participants: 0
      });
    }
    setOpenDialog(true);
  };
  
  // Закрыть диалог
  const handleCloseDialog = () => {
    setOpenDialog(false);
    setEditRaffle(null);
  };
  
  const handleFormChange = (e: React.ChangeEvent<HTMLInputElement | { name?: string; value: unknown }>) => {
    const name = e.target.name as string;
    const value = e.target.value;
    setForm({ ...form, [name]: value });
  };
  
  const handleSelectChange = (e: SelectChangeEvent) => {
    const { name, value } = e.target;
    setForm({ ...form, [name]: value });
  };
  
  const handleSaveRaffle = async () => {
    try {
      const raffleData = {
        ...form,
        totalTickets: parseInt(form.totalTickets),
        price: parseFloat(form.price),
        year: parseInt(form.year)
      };
      
      if (editRaffle) {
        // Update existing raffle
        const raffleRef = doc(db, 'raffles', editRaffle.id);
        await updateDoc(raffleRef, raffleData);
      } else {
        // Create new raffle
        await addDoc(collection(db, 'raffles'), {
          ...raffleData,
          createdAt: new Date()
        });
      }
      
      handleCloseDialog();
      refreshData();
    } catch (error) {
      console.error("Error saving raffle:", error);
    }
  };
  
  const handleDeleteRaffle = async (id: string) => {
    if (window.confirm('Вы уверены, что хотите удалить этот розыгрыш?')) {
      try {
        const raffleRef = doc(db, 'raffles', id);
        await deleteDoc(raffleRef);
        refreshData();
      } catch (error) {
        console.error("Error deleting raffle:", error);
      }
    }
  };
  
  const getStatusColor = (status: string) => {
    switch (status) {
      case 'active':
        return theme.palette.success.main;
      case 'completed':
        return theme.palette.info.main;
      case 'draft':
        return theme.palette.warning.main;
      default:
        return theme.palette.error.main;
    }
  };
  
  const getStatusLabel = (status: string) => {
    switch (status) {
      case 'active':
        return 'Активный';
      case 'completed':
        return 'Завершен';
      case 'draft':
        return 'Черновик';
      default:
        return 'Отменен';
    }
  };
  
  // Open car specifications dialog
  const handleOpenCarSpecs = (raffle: Raffle) => {
    setSelectedRaffle(raffle);
    setOpenCarSpecsDialog(true);
  };
  
  // Close car specifications dialog
  const handleCloseCarSpecs = () => {
    setOpenCarSpecsDialog(false);
    setSelectedRaffle(null);
  };
  
  const handleViewCarSpecs = (raffle: Raffle) => {
    if (raffle.carSpecifications) {
      setSelectedRaffle(raffle);
      setViewCarSpecsModal(true);
    }
  };
  
  const handleCloseViewCarSpecs = () => {
    setViewCarSpecsModal(false);
  };
  
  return (
    <Box sx={{ maxWidth: 1200, margin: '0 auto', padding: { xs: 2, md: 3 } }}>
      <AdminHeader>
        <Box>
          <Typography variant="h4" component="h1" gutterBottom fontWeight="bold">
            Панель администратора
          </Typography>
          <Typography variant="subtitle1">
            Управляйте розыгрышами, компаниями и настройками
          </Typography>
        </Box>
        <IconButton color="inherit">
          <Settings />
        </IconButton>
      </AdminHeader>
      
      {/* Табы для разных разделов */}
      <Box sx={{ mb: 3 }}>
        <Tabs 
          value={tabValue}
          onChange={handleTabChange}
          variant="scrollable"
          scrollButtons="auto"
          aria-label="admin tabs"
          sx={{
            '& .MuiTab-root': {
              minWidth: 'auto',
              px: 3,
              py: 2,
            }
          }}
        >
          <Tab 
            icon={<CardGiftcard />} 
            iconPosition="start"
            label="Розыгрыши" 
            id="admin-tab-0" 
          />
          <Tab 
            icon={<DirectionsCar />} 
            iconPosition="start"
            label="Автомобили" 
            id="admin-tab-1" 
          />
          <Tab 
            icon={<Business />} 
            iconPosition="start"
            label="Компании" 
            id="admin-tab-2" 
          />
          <Tab 
            icon={<Storage />} 
            iconPosition="start"
            label="База данных" 
            id="admin-tab-3" 
          />
          <Tab 
            icon={<Settings />} 
            iconPosition="start"
            label="Настройки" 
            id="admin-tab-4" 
          />
        </Tabs>
      </Box>
      
      {/* Раздел статистики (только на вкладке Розыгрыши) */}
      <TabPanel value={tabValue} index={0}>
        <Typography variant="h5" gutterBottom>
          Сводная статистика
        </Typography>
        
        <GridContainer spacing={3}>
          {statsData.map((stat, index) => (
            <GridItem xs={12} md={4} key={index}>
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
              >
                <StatsCard>
                  <CardContent sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                    <StatsIcon>
                      {stat.icon}
                    </StatsIcon>
                    <Typography variant="h4" component="div" fontWeight="bold">
                      {stat.value.toLocaleString()}
                    </Typography>
                    <Typography variant="subtitle1" color="textSecondary" gutterBottom>
                      {stat.title}
                    </Typography>
                    <Typography variant="body2" color="textSecondary">
                      {stat.change}
                    </Typography>
                  </CardContent>
                </StatsCard>
              </motion.div>
            </GridItem>
          ))}
        </GridContainer>
        
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mt: 4, mb: 2 }}>
          <Typography variant="h5">
            Список розыгрышей
          </Typography>
          <Button 
            variant="contained" 
            startIcon={<Add />}
            onClick={() => handleOpenDialog()}
          >
            Добавить розыгрыш
          </Button>
        </Box>
        
        <TablePaper>
          <TableContainer>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Название</TableCell>
                  <TableCell>Компания</TableCell>
                  <TableCell align="center">Год</TableCell>
                  <TableCell align="center">Билеты</TableCell>
                  <TableCell align="center">Цена</TableCell>
                  <TableCell align="center">Статус</TableCell>
                  <TableCell align="center">Действия</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {raffles.map((raffle) => (
                  <TableRow key={raffle.id}>
                    <TableCell>
                      <Box sx={{ display: 'flex', alignItems: 'center' }}>
                        {raffle.images && raffle.images.length > 0 ? (
                          <Box
                            component="img"
                            src={raffle.images[0]}
                            alt={raffle.title}
                            sx={{ width: 48, height: 48, borderRadius: 1, objectFit: 'cover', mr: 2 }}
                          />
                        ) : (
                          <Box
                            sx={{ 
                              width: 48, 
                              height: 48, 
                              borderRadius: 1,
                              bgcolor: 'grey.200',
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'center',
                              mr: 2
                            }}
                          >
                            <DirectionsCar />
                          </Box>
                        )}
                        <Typography variant="body1">{raffle.title}</Typography>
                      </Box>
                    </TableCell>
                    <TableCell>
                      {companies.find(c => c.id === raffle.companyId)?.name || 'Нет компании'}
                    </TableCell>
                    <TableCell align="center">{raffle.year}</TableCell>
                    <TableCell align="center">
                      {raffle.ticketsSold} / {raffle.totalTickets}
                    </TableCell>
                    <TableCell align="center">{raffle.price.toLocaleString()} ₽</TableCell>
                    <TableCell align="center">
                      <Chip 
                        label={getStatusLabel(raffle.status)} 
                        size="small"
                        sx={{ 
                          bgcolor: alpha(getStatusColor(raffle.status), 0.1),
                          color: getStatusColor(raffle.status),
                          fontWeight: 'medium'
                        }}
                      />
                    </TableCell>
                    <TableCell align="center">
                      <IconButton size="small" onClick={() => handleOpenDialog(raffle)}>
                        <Edit fontSize="small" />
                      </IconButton>
                      <IconButton size="small" onClick={() => handleViewCarSpecs(raffle)}>
                        <DirectionsCar fontSize="small" />
                      </IconButton>
                      <IconButton size="small" onClick={() => handleDeleteRaffle(raffle.id)}>
                        <Delete fontSize="small" />
                      </IconButton>
                    </TableCell>
                  </TableRow>
                ))}
                {raffles.length === 0 && (
                  <TableRow>
                    <TableCell colSpan={7} align="center" sx={{ py: 3 }}>
                      <Typography color="textSecondary">
                        Нет доступных розыгрышей. Нажмите "Добавить розыгрыш", чтобы создать первый.
                      </Typography>
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </TableContainer>
        </TablePaper>
      </TabPanel>
      
      {/* Раздел Автомобили */}
      <TabPanel value={tabValue} index={1}>
        <AdminHeader>
          <Typography variant="h5" color="inherit">
            Характеристики автомобилей
          </Typography>
        </AdminHeader>
        
        <TablePaper>
          <TableContainer>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Модель</TableCell>
                  <TableCell>Компания</TableCell>
                  <TableCell>Статус</TableCell>
                  <TableCell align="right">Действия</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {raffles.map((raffle) => (
                  <TableRow key={raffle.id}>
                    <TableCell>{raffle.title}</TableCell>
                    <TableCell>
                      {companies.find(c => c.id === raffle.companyId)?.name || '-'}
                    </TableCell>
                    <TableCell>
                      <Chip 
                        label={getStatusLabel(raffle.status)} 
                        sx={{ bgcolor: getStatusColor(raffle.status), color: 'white' }}
                        size="small"
                      />
                    </TableCell>
                    <TableCell align="right">
                      {raffle.carSpecifications && (
                        <Button 
                          variant="outlined" 
                          size="small" 
                          onClick={() => handleViewCarSpecs(raffle)}
                          sx={{ mr: 1 }}
                        >
                          Просмотреть
                        </Button>
                      )}
                      <Button 
                        variant="contained" 
                        color="primary" 
                        size="small"
                        onClick={() => handleOpenCarSpecs(raffle)}
                      >
                        {raffle.carSpecifications ? "Редактировать" : "Добавить"}
                      </Button>
                    </TableCell>
                  </TableRow>
                ))}
                {raffles.length === 0 && (
                  <TableRow>
                    <TableCell colSpan={5} align="center" sx={{ py: 3 }}>
                      <Typography color="textSecondary">
                        Нет доступных автомобилей. Сначала добавьте розыгрыш во вкладке "Розыгрыши".
                      </Typography>
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </TableContainer>
        </TablePaper>
      </TabPanel>
      
      {/* Раздел Компании */}
      <TabPanel value={tabValue} index={2}>
        <CompaniesManager />
      </TabPanel>
      
      {/* Раздел База данных */}
      <TabPanel value={tabValue} index={3}>
        <Typography variant="h5" gutterBottom>
          Управление базой данных
        </Typography>
        
        <Typography variant="body1" paragraph>
          Здесь вы можете управлять структурой базы данных и выполнять служебные операции.
        </Typography>
        
        <DatabaseMigration />
      </TabPanel>
      
      {/* Раздел Настройки */}
      <TabPanel value={tabValue} index={4}>
        <Typography variant="h5" gutterBottom>
          Настройки приложения
        </Typography>
        
        <Typography variant="body1" paragraph>
          Здесь вы можете настроить основные параметры приложения, включая название, логотип и изображения.
        </Typography>
        
        <AppSettingsForm />
      </TabPanel>
      
      {/* Диалог создания/редактирования розыгрыша */}
      <Dialog open={openDialog} onClose={handleCloseDialog} maxWidth="md" fullWidth>
        <DialogTitle>
          {editRaffle ? `Редактирование: ${editRaffle.title}` : 'Новый розыгрыш'}
        </DialogTitle>
        <DialogContent>
          <TextField
            fullWidth
            margin="normal"
            label="Название"
            name="title"
            value={form.title}
            onChange={handleFormChange}
          />
          <TextField
            fullWidth
            margin="normal"
            label="URL изображения"
            name="image"
            value={form.image}
            onChange={handleFormChange}
          />
          <TextField
            fullWidth
            margin="normal"
            label="Описание"
            name="description"
            multiline
            rows={3}
            value={form.description}
            onChange={handleFormChange}
          />
          
          <GridContainer spacing={2}>
            <GridItem xs={12} md={6}>
              <TextField
                fullWidth
                margin="normal"
                label="Всего билетов"
                name="totalTickets"
                type="number"
                value={form.totalTickets}
                onChange={handleFormChange}
              />
            </GridItem>
            <GridItem xs={12} md={6}>
              <TextField
                fullWidth
                margin="normal"
                label="Цена за билет"
                name="price"
                type="number"
                value={form.price}
                onChange={handleFormChange}
              />
            </GridItem>
            <GridItem xs={12} md={6}>
              <TextField
                fullWidth
                margin="normal"
                label="Год выпуска"
                name="year"
                type="number"
                value={form.year}
                onChange={handleFormChange}
              />
            </GridItem>
            <GridItem xs={12} md={6}>
              <TextField
                fullWidth
                margin="normal"
                label="Дата окончания"
                name="endDate"
                type="date"
                InputLabelProps={{ shrink: true }}
                value={form.endDate}
                onChange={handleFormChange}
              />
            </GridItem>
            <GridItem xs={12} md={6}>
              <FormControl fullWidth margin="normal">
                <InputLabel>Статус</InputLabel>
                <Select
                  name="status"
                  value={form.status}
                  label="Статус"
                  onChange={handleSelectChange}
                >
                  <MenuItem value="draft">Черновик</MenuItem>
                  <MenuItem value="active">Активный</MenuItem>
                  <MenuItem value="completed">Завершен</MenuItem>
                  <MenuItem value="canceled">Отменен</MenuItem>
                </Select>
              </FormControl>
            </GridItem>
            <GridItem xs={12} md={6}>
              <FormControl fullWidth margin="normal">
                <InputLabel>Компания</InputLabel>
                <Select
                  name="companyId"
                  value={form.companyId}
                  label="Компания"
                  onChange={handleSelectChange}
                >
                  {companies.map((company) => (
                    <MenuItem key={company.id} value={company.id}>
                      {company.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </GridItem>
          </GridContainer>
        </DialogContent>
        <DialogActions sx={{ px: 3, pb: 3 }}>
          <Button onClick={handleCloseDialog}>Отмена</Button>
          <Button
            onClick={handleSaveRaffle}
            variant="contained"
            disabled={!form.title || !form.companyId}
          >
            {editRaffle ? 'Обновить' : 'Создать'}
          </Button>
        </DialogActions>
      </Dialog>
      
      {/* Диалог для просмотра спецификаций автомобиля */}
      <Dialog 
        open={viewCarSpecsModal} 
        onClose={handleCloseViewCarSpecs}
        maxWidth="lg"
        fullWidth
      >
        <DialogContent>
          {selectedRaffle && (
            <CarSpecificationsModal
              open={true}
              onClose={handleCloseViewCarSpecs}
              carSpecs={selectedRaffle.carSpecifications}
              features={selectedRaffle.features as any[]}
            />
          )}
        </DialogContent>
      </Dialog>
      
      {/* Диалог для редактирования спецификаций автомобиля */}
      <Dialog 
        open={openCarSpecsDialog} 
        onClose={handleCloseCarSpecs}
        maxWidth="lg"
        fullWidth
      >
        <DialogContent>
          {selectedRaffle && (
            <CarSpecificationsForm
              raffle={selectedRaffle}
              onCancel={handleCloseCarSpecs}
              onSaved={handleCloseCarSpecs}
            />
          )}
        </DialogContent>
      </Dialog>
    </Box>
  );
};

export default AdminPage;
